import React, { useState, useRef, useEffect } from 'react';
import { PanelBase } from '../index';
import { aiAPI } from '../../services/api';
import useStore from '../../store/useStore';

const QUICK = [
  'Ada kemacetan di Palembang sekarang?',
  'SPBU terdekat dari lokasi saya',
  'Kondisi cuaca Palembang hari ini',
  'Rute tercepat ke Jembatan Ampera',
  'Tips berkendara saat hujan',
  'Area mana yang paling ramai permintaan driver?',
];

export default function AIChatPanel({ isOpen, onClose, userLocation, weather, route, destination }) {
  const { aiMessages, addAIMessage, user } = useStore();
  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);
  const scrollRef = useRef(null);

  useEffect(() => {
    if (aiMessages.length === 0) {
      const h = new Date().getHours();
      const gr = h < 12 ? 'Selamat pagi' : h < 17 ? 'Selamat siang' : 'Selamat sore';
      addAIMessage({
        role: 'assistant',
        content: `${gr}! Saya RouteAI, asisten navigasi cerdas Anda.\n\nKetik pertanyaan Anda!`,
        ts: new Date()
      });
    }
  }, []);

  useEffect(() => {
    if (scrollRef.current) scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
  }, [aiMessages, loading]);

  const send = async (text) => {
    const msg = (text || input).trim();
    if (!msg || loading) return;
    setInput('');
    addAIMessage({ role: 'user', content: msg, ts: new Date() });
    setLoading(true);
    try {
      const history = aiMessages.slice(-8).map(m => ({ role: m.role, content: m.content }));
      const context = {
        city: 'Palembang',
        weather: weather?.temperature ? `${weather.temperature}°C, ${weather.description}` : 'Berawan',
        userLocation: userLocation ? `${userLocation.lat},${userLocation.lng}` : 'Palembang',
        activeRoute: destination ? { to: destination.name } : null,
        vehicle: user?.preferences?.vehicle || 'Mobil'
      };
      const res = await aiAPI.chat(msg, history, context);
      addAIMessage({ role: 'assistant', content: res.data.data.reply, ts: new Date() });
    } catch (err) {
      addAIMessage({ role: 'assistant', content: 'Maaf, AI sedang sibuk. Coba lagi nanti.', ts: new Date() });
    }
    setLoading(false);
  };

  return (
    <PanelBase isOpen={isOpen} onClose={onClose} title="RouteAI Chat">
      <div>
        {/* Quick prompts */}
        <div style={{ display: 'flex', gap: 7, overflowX: 'auto', marginBottom: 12 }}>
          {QUICK.map((q, i) => (
            <button key={i} onClick={() => send(q)} style={{ padding: '5px 10px', background: '#21262D', borderRadius: 14, fontSize: 12, border: 'none', color: '#F0F6FC' }}>
              {q}
            </button>
          ))}
        </div>

        {/* Messages */}
        <div ref={scrollRef} style={{ maxHeight: 300, overflowY: 'auto', marginBottom: 12 }}>
          {aiMessages.map((m, i) => (
            <div key={i} style={{ marginBottom: 8, textAlign: m.role === 'user' ? 'right' : 'left' }}>
              <div style={{ display: 'inline-block', maxWidth: '80%', padding: '8px 12px', borderRadius: 12, background: m.role === 'user' ? '#6B5CE7' : '#21262D', color: '#F0F6FC' }}>
                {m.role === 'assistant' && <strong style={{ color: '#7B6FFF' }}>RouteAI</strong>}
                <div style={{ whiteSpace: 'pre-line' }}>{m.content}</div>
              </div>
            </div>
          ))}
          {loading && <div>Loading...</div>}
        </div>

        {/* Input */}
        <div style={{ borderTop: '0.5px solid rgba(255,255,255,0.07)', paddingTop: 12, display: 'flex', gap: 8 }}>
          <input
            style={{ flex: 1, padding: '10px', backgroundColor: '#21262D', border: '0.5px solid rgba(255,255,255,0.1)', borderRadius: 8, color: '#F0F6FC' }}
            placeholder="Tanya RouteAI..."
            value={input}
            onChange={e => setInput(e.target.value)}
            onKeyPress={e => e.key === 'Enter' && send()}
            autoFocus
          />
          <button onClick={() => send()} style={{ padding: '10px 16px', background: '#6B5CE7', border: 'none', borderRadius: 8, color: '#fff' }}>
            Kirim
          </button>
        </div>
      </div>
    </PanelBase>
  );
}
